#include<bits/stdc++.h>
using namespace std;
int a[101],b[101],s[101],n,c,f[101][101][2];
int main()
{
    scanf("%d%d",&n,&c);
    memset(f,0x3f,sizeof(f));
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&a[i],&b[i]);
        s[i]=s[i-1]+b[i];
    }
    f[c][c][0]=f[c][c][1]=0;
    for(int len=2;len<=n;len++)
    {
        for(int l=1,r=len;r<=n;l++,r++)
        {
            f[l][r][0]=min(f[l+1][r][0]+(a[l+1]-a[l])*(s[l]+s[n]-s[r]),f[l+1][r][1]+(a[r]-a[l])*(s[l]+s[n]-s[r]));
            f[l][r][1]=min(f[l][r-1][0]+(a[r]-a[l])*(s[l-1]+s[n]-s[r-1]),f[l][r-1][1]+(a[r]-a[r-1])*(s[l-1]+s[n]-s[r-1]));
        }
    }
    printf("%d",min(f[1][n][0],f[1][n][1]));
    return 0;
}
